  9→import org.junit.Test
 10→import kotlin.test.*
 11→
 12→@Suppress("UNREACHABLE_CODE", "UNUSED", "UNUSED_PARAMETER")
 13→class StackTraceRecoveryCustomExceptionsTest : TestBase() {
 14→
 15→    internal class NonCopyable(val customData: Int) : Throwable() {
 16→        // Bait
 17→        public constructor(cause: Throwable) : this(42)
 18→    }
 19→
 20→    internal class Copyable(val customData: Int) : Throwable(), CopyableThrowable<Copyable> {
 21→        // Bait
 22→        public constructor(cause: Throwable) : this(42)
 23→
 24→        override fun createCopy(): Copyable {
 25→            val copy = Copyable(customData)
 26→            copy.initCause(this)
 27→            return copy
 28→        }
 29→    }
 30→
 31→    @Test
 32→    fun testStackTraceNotRecovered() = runTest {
 33→        try {
 34→            withContext(wrapperDispatcher(coroutineContext)) {
 35→                throw NonCopyable(239)
 36→            }
 37→            expectUnreached()
 38→        } catch (e: NonCopyable) {
 39→            assertEquals(239, e.customData)
 40→            assertNull(e.cause)
 41→        }
 42→    }
 43→
 44→    @Test
 45→    fun testStackTraceRecovered() = runTest {
 46→        try {
 47→            withContext(wrapperDispatcher(coroutineContext)) {
 48→                throw Copyable(239)
 49→            }
 50→            expectUnreached()
 51→        } catch (e: Copyable) {
 52→            assertEquals(239, e.customData)
 53→            val cause = e.cause
 54→            assertTrue(cause is Copyable)
 55→            assertEquals(239, cause.customData)
 56→        }
 57→    }
 58→
 59→    internal class WithDefault(message: String = "default") : Exception(message)
 60→
 61→    @Test
 62→    fun testStackTraceRecoveredWithCustomMessage() = runTest {
 63→        try {
 64→            withContext(wrapperDispatcher(coroutineContext)) {
 65→                throw WithDefault("custom")
 66→            }
 67→            expectUnreached()
 68→        } catch (e: WithDefault) {
 69→            assertEquals("custom", e.message)
 70→            val cause = e.cause
 71→            assertTrue(cause is WithDefault)
 72→            assertEquals("custom", cause.message)
 73→        }
 74→    }
 75→
 76→    class WrongMessageException(token: String) : RuntimeException("Token $token")
 77→
 78→    @Test
 79→    fun testWrongMessageException() = runTest {
 80→        val result = runCatching {
 81→            coroutineScope<Unit> {
 82→                throw WrongMessageException("OK")
 83→            }
 84→        }
 85→        val ex = result.exceptionOrNull() ?: error("Expected to fail")
 86→        assertTrue(ex is WrongMessageException)
 87→        assertEquals("Token OK", ex.message)
 88→    }
 89→
 90→    @Test
 91→    fun testWrongMessageExceptionInChannel() = runTest {
 92→        val result = produce<Unit>(SupervisorJob() + Dispatchers.Unconfined) {
 93→            throw WrongMessageException("OK")
 94→        }
 95→        val ex = runCatching {
 96→            @Suppress("ControlFlowWithEmptyBody")
 97→            for (unit in result) {
 98→                // Iterator has a special code path
 99→            }
100→        }.exceptionOrNull() ?: error("Expected to fail")
101→        assertTrue(ex is WrongMessageException)
102→        assertEquals("Token OK", ex.message)
103→    }
104→
105→    class CopyableWithCustomMessage(
106→        message: String?,
107→        cause: Throwable? = null
108→    ) : RuntimeException(message, cause),
109→        CopyableThrowable<CopyableWithCustomMessage> {
110→
111→        override fun createCopy(): CopyableWithCustomMessage {
112→            return CopyableWithCustomMessage("Recovered: [$message]", cause)
113→        }
114→    }
115→
116→    @Test
117→    fun testCustomCopyableMessage() = runTest {
118→        val result = runCatching {
119→            coroutineScope<Unit> {
120→                throw CopyableWithCustomMessage("OK")
121→            }
122→        }
123→        val ex = result.exceptionOrNull() ?: error("Expected to fail")
124→        assertTrue(ex is CopyableWithCustomMessage)
125→        assertEquals("Recovered: [OK]", ex.message)
126→    }
127→
128→    @Test
129→    fun testTryCopyThrows() = runTest {
130→        class FailingException : Exception(), CopyableThrowable<FailingException> {
131→            override fun createCopy(): FailingException? {
132→                TODO("Not yet implemented")
133→            }
134→        }
135→
136→        val e = FailingException()
137→        val result = runCatching {
138→            coroutineScope<Unit> {
139→                throw e
140→            }
141→        }
142→
143→        assertSame(e, result.exceptionOrNull())
144→    }
145→}
