     * Exception with message+cause constructor (should be preferred).
     * When stack trace recovery is enabled, a copy is made with the original as the cause (for stack trace chaining).
     */
    class MessageAndCauseException : RuntimeException {
        constructor(message: String, cause: Throwable) : super(message, cause)
        constructor(message: String) : super(message)
        constructor(cause: Throwable) : super(cause)
        constructor() : super()
    }

    @Test
    fun testMessageAndCauseException() = runTest {
        val cause = IllegalStateException("Original cause")
        val result = runCatching {
            coroutineScope<Unit> {
                throw MessageAndCauseException("Custom message", cause)
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is MessageAndCauseException, "Expected MessageAndCauseException but got ${ex::class}")
        assertEquals("Custom message", ex.message)
        // With (String, Throwable) constructor available, stack trace recovery creates a copy
        // The copy's cause is the original exception (for stack trace chaining)
        val exCause = ex.cause
        assertTrue(exCause is MessageAndCauseException, "Expected cause to be MessageAndCauseException but got ${exCause?.let { it::class }}")
        // The original exception's cause should be the IllegalStateException
        assertTrue(exCause.cause is IllegalStateException, "Expected original's cause to be IllegalStateException but got ${exCause.cause?.let { it::class }}")
    }"}

