  5→package kotlinx.coroutines.internal
  6→
  7→import kotlinx.coroutines.*
  8→import java.lang.reflect.*
  9→import java.util.*
 10→import java.util.concurrent.locks.*
 11→import kotlin.concurrent.*
 12→
 13→private val throwableFields = Throwable::class.java.fieldsCountOrDefault(-1)
 14→private typealias Ctor = (Throwable) -> Throwable?
 15→
 16→private val ctorCache = try {
 17→    if (ANDROID_DETECTED) WeakMapCtorCache
 18→    else ClassValueCtorCache
 19→} catch (e: Throwable) {
 20→    // Fallback on Java 6 or exotic setups
 21→    WeakMapCtorCache
 22→}
 23→
 24→@Suppress("UNCHECKED_CAST")
 25→internal fun <E : Throwable> tryCopyException(exception: E): E? {
 26→    // Fast path for CopyableThrowable
 27→    if (exception is CopyableThrowable<*>) {
 28→        return runCatching { exception.createCopy() as E? }.getOrNull()
 29→    }
 30→    return ctorCache.get(exception.javaClass).invoke(exception) as E?
 31→}
 32→
 33→private fun <E : Throwable> createConstructor(clz: Class<E>): Ctor {
 34→    val nullResult: Ctor = { null } // Pre-cache class
 35→    // Skip reflective copy if an exception has additional fields (that are usually populated in user-defined constructors)
 36→    if (throwableFields != clz.fieldsCountOrDefault(0)) return nullResult
 37→    /*
 38→    * Try to reflectively find constructor(), constructor(message, cause), constructor(cause) or constructor(message).
 39→    * Exceptions are shared among coroutines, so we should copy exception before recovering current stacktrace.
 40→    *
 41→    * Constructors are prioritized as follows:
 42→    * 1) constructor(message, cause)  - Throwable(String, Throwable)
 43→    * 2) constructor(cause)            - Throwable(Throwable)
 44→    * 3) constructor(message)          - Throwable(String) + initCause
 45→    * 4) constructor()                 - Throwable() + initCause
 46→    */
 47→    var bestCtor: Ctor? = null
 48→    var bestCtorPriority = -1
 49→    for (constructor in clz.constructors) {
 50→        val (priority, ctor) = createSafeConstructorWithPriority(constructor)
 51→        if (ctor != null && priority > bestCtorPriority) {
 52→            bestCtorPriority = priority
 53→            bestCtor = ctor
 54→        }
 55→    }
 56→    return bestCtor ?: nullResult
 57→}
 58→
 59→/*
 60→ * Returns a pair of (priority, constructor) where priority indicates preference:
 61→ * 4 = (String, Throwable) - best, copies message and preserves cause chain
 62→ * 3 = (Throwable) - good, preserves cause properly
 63→ * 2 = (String) - copies message but wraps exception as cause (can cause incorrect nesting)
 64→ * 1 = () - fallback, no params
 65→ * -1 = not viable
 66→ */
 67→private fun createSafeConstructorWithPriority(constructor: Constructor<*>): Pair<Int, Ctor?> {
 68→    val p = constructor.parameterTypes
 69→    return when (p.size) {
 70→        2 -> when {
 71→            p[0] == String::class.java && p[1] == Throwable::class.java ->
 72→                4 to safeCtor { e -> constructor.newInstance(e.message, e) as Throwable }
 73→            else -> -1 to null
 74→        }
 75→        1 -> when (p[0]) {
 76→            Throwable::class.java ->
 77→                3 to safeCtor { e -> constructor.newInstance(e) as Throwable }
 78→            String::class.java ->
 79→                2 to safeCtor { e -> (constructor.newInstance(e.message) as Throwable).also { it.initCause(e) } }
 80→            else -> -1 to null
 81→        }
 82→        0 -> 1 to safeCtor { e -> (constructor.newInstance() as Throwable).also { it.initCause(e) } }
 83→        else -> -1 to null
 84→    }
 85→}
 86→
 87→private inline fun safeCtor(crossinline block: (Throwable) -> Throwable): Ctor =
 88→    { e -> runCatching { block(e) }.getOrNull() }
 89→
 90→private fun Class<*>.fieldsCountOrDefault(defaultValue: Int) =
 91→    kotlin.runCatching { fieldsCount() }.getOrDefault(defaultValue)
 92→
 93→private tailrec fun Class<*>.fieldsCount(accumulator: Int = 0): Int {
 94→    val fieldsCount = declaredFields.count { !Modifier.isStatic(it.modifiers) }
 95→    val totalFields = accumulator + fieldsCount
 96→    val superClass = superclass ?: return totalFields
 97→    return superClass.fieldsCount(totalFields)
 98→}
 99→
100→internal abstract class CtorCache {
101→    abstract fun get(key: Class<out Throwable>): Ctor
102→}
103→
104→private object WeakMapCtorCache : CtorCache() {
105→    private val cacheLock = ReentrantReadWriteLock()
106→    private val exceptionCtors: WeakHashMap<Class<out Throwable>, Ctor> = WeakHashMap()
107→
108→    override fun get(key: Class<out Throwable>): Ctor {
109→        cacheLock.read { exceptionCtors[key]?.let { return it } }
110→        cacheLock.write {
111→            exceptionCtors[key]?.let { return it }
112→            return createConstructor(key).also { exceptionCtors[key] = it }
113→        }
114→    }
115→}
116→
117→@IgnoreJreRequirement
118→private object ClassValueCtorCache : CtorCache() {
119→    private val cache = object : ClassValue<Ctor>() {
120→        override fun computeValue(type: Class<*>?): Ctor {
121→            @Suppress("UNCHECKED_CAST")
122→            return createConstructor(type as Class<out Throwable>)
123→        }
124→    }
125→
126→    override fun get(key: Class<out Throwable>): Ctor = cache.get(key)
127→}
