package kotlinx.coroutines.exceptions

import kotlinx.coroutines.*
import org.junit.Test
import kotlin.test.*

/**
 * Tests for the bug where recoverStackTrace causes nested exceptions when an exception
 * has both String and Throwable constructors in certain orders.
 * 
 * See: https://github.com/Kotlin/kotlinx.coroutines/issues/3631
 */
class StackTraceRecoveryNestedExceptionTest : TestBase() {

    /**
     * Exception with String constructor declared before Throwable constructor.
     * This was causing the bug because the String constructor was being selected
     * instead of the Throwable constructor.
     */
    class NestedExceptionStringFirst : RuntimeException {
        constructor(message: String) : super(message)
        constructor(cause: Throwable) : super(cause)
        constructor() : super()
    }

    /**
     * Exception with Throwable constructor declared before String constructor.
     * This was working correctly by chance because of constructor ordering.
     */
    class NestedExceptionThrowableFirst : RuntimeException {
        constructor(cause: Throwable) : super(cause)
        constructor(message: String) : super(message)
        constructor() : super()
    }

    @Test
    fun testNestedExceptionStringFirstConstructor() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedExceptionStringFirst(IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedExceptionStringFirst, "Expected NestedExceptionStringFirst but got ${ex::class}")
        assertTrue(ex.cause is IllegalStateException, "Expected cause to be IllegalStateException but got ${ex.cause?.let { it::class }}")
        assertEquals("ERROR", (ex.cause as IllegalStateException).message)
    }

    @Test
    fun testNestedExceptionThrowableFirstConstructor() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedExceptionThrowableFirst(IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedExceptionThrowableFirst, "Expected NestedExceptionThrowableFirst but got ${ex::class}")
        assertTrue(ex.cause is IllegalStateException, "Expected cause to be IllegalStateException but got ${ex.cause?.let { it::class }}")
        assertEquals("ERROR", (ex.cause as IllegalStateException).message)
    }

    /**
     * Exception that only has a String constructor (should still work with initCause).
     */
    class StringOnlyException(message: String) : RuntimeException(message)

    @Test
    fun testStringOnlyException() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw StringOnlyException("Test message")
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is StringOnlyException, "Expected StringOnlyException but got ${ex::class}")
        assertEquals("Test message", ex.message)
    }

    /**
     * Exception that only has a Throwable constructor.
     */
    class ThrowableOnlyException(cause: Throwable) : RuntimeException(cause)

    @Test
    fun testThrowableOnlyException() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw ThrowableOnlyException(IllegalStateException("Cause message"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is ThrowableOnlyException, "Expected ThrowableOnlyException but got ${ex::class}")
        assertTrue(ex.cause is IllegalStateException, "Expected cause to be IllegalStateException but got ${ex.cause?.let { it::class }}")
        assertEquals("Cause message", (ex.cause as IllegalStateException).message)
    }

    /**
     * Exception with message+cause constructor (should be preferred).
     */
    class MessageAndCauseException : RuntimeException {
        constructor(message: String, cause: Throwable) : super(message, cause)
        constructor(message: String) : super(message)
        constructor(cause: Throwable) : super(cause)
        constructor() : super()
    }

    @Test
    fun testMessageAndCauseException() = runTest {
        val cause = IllegalStateException("Original cause")
        val result = runCatching {
            coroutineScope<Unit> {
                throw MessageAndCauseException("Custom message", cause)
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is MessageAndCauseException, "Expected MessageAndCauseException but got ${ex::class}")
        assertEquals("Custom message", ex.message)
        assertTrue(ex.cause is IllegalStateException, "Expected cause to be IllegalStateException but got ${ex.cause?.let { it::class }}")
    }

    /**
     * Test that demonstrates the original bug scenario from the issue.
     */
    @Test
    fun testOriginalBugScenario() = runTest {
        // Create exception: TestException(IllegalStateException("test"))
        // Without fix: TestException(TestException(IllegalStateException("test"))) - wrong!
        // With fix: TestException(IllegalStateException("test")) - correct!

        class TestException : RuntimeException {
            constructor(message: String) : super(message)
            constructor(cause: Throwable) : super(cause)
            constructor() : super()
        }

        val result = runCatching {
            coroutineScope<Unit> {
                throw TestException(IllegalStateException("test"))
            }
        }

        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is TestException, "Expected TestException but got ${ex::class}")

        // The cause should be IllegalStateException, not another TestException
        val cause = ex.cause
        assertTrue(cause is IllegalStateException, 
            "Expected cause to be IllegalStateException but got ${cause?.let { it::class }}. " +
            "This indicates the bug where exception is incorrectly nested.")
        assertEquals("test", cause.message)
    }
}
"}

