 93→private tailrec fun Class<*>.fieldsCount(accumulator: Int = 0): Int {
 94→    val fieldsCount = declaredFields.count { !Modifier.isStatic(it.modifiers) }
 95→    val totalFields = accumulator + fieldsCount
 96→    val superClass = superclass ?: return totalFields
 97→    return superClass.fieldsCount(totalFields)
 98→}
