100→internal abstract class CtorCache {
101→    abstract fun get(key: Class<out Throwable>): Ctor
102→}
103→
104→private object WeakMapCtorCache : CtorCache() {
105→    private val cacheLock = ReentrantReadWriteLock()
106→    private val exceptionCtors: WeakHashMap<Class<out Throwable>, Ctor> = WeakHashMap()
107→
108→    override fun get(key: Class<out Throwable>): Ctor {
109→        cacheLock.read { exceptionCtors[key]?.let { return it } }
110→        cacheLock.write {
111→            exceptionCtors[key]?.let { return it }
112→            return createConstructor(key).also { exceptionCtors[key] = it }
113→        }
114→    }
115→}
116→
117→@IgnoreJreRequirement
118→private object ClassValueCtorCache : CtorCache() {
119→    private val cache = object : ClassValue<Ctor>() {
120→        override fun computeValue(type: Class<*>?): Ctor {
121→            @Suppress("UNCHECKED_CAST")
122→            return createConstructor(type as Class<out Throwable>)
123→        }
124→    }
125→
126→    override fun get(key: Class<out Throwable>): Ctor = cache.get(key)
127→}
